+function findLastPositionalArg(parts: string[]): string | undefined {
+  for (let index = parts.length - 1; index >= 1; index -= 1) {
+    const part = parts[index];
+    if (!part) {
+      continue;
+    }
+    if (part.startsWith('-')) {
+      continue;
+    }
+    if (/^[A-Za-z0-9_]+=/.test(part)) {
+      continue;
+    }
+    if (part.includes('://')) {
+      continue;
+    }
+    return part;
+  }
+  return undefined;
+}
